class Solution {
    public int maxScore(int[] nums) {
        int n = nums.length / 2;
        int[] dp = new int[1 << n];
        for (int mask = 1; mask < (1 << n); mask++) {
            int i = Integer.numberOfTrailingZeros(mask);
            for (int j = i + 1; j < n; j++) {
                if ((mask & (1 << j)) != 0) {
                    int prevMask = mask ^ (1 << i) ^ (1 << j);
                    dp[mask] = Math.max(dp[mask], dp[prevMask] + (i + 1) * gcd(nums[i], nums[j]));
                }
            }
        }
        return dp[(1 << n) - 1];

    }
    public int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}
